mapper.select:
select mn_num, mn_name, device_brand, device_model, device_quantity, setup_time, lifespan, life_unit, create_time, update_time
from t_device_info
where mn_num = #{mnNum}

select mn_num, mn_name, device_brand, device_model, device_quantity, setup_time, lifespan, life_unit, create_time, update_time
from t_device_info i


        and exists (select 1 from t_ent_out_put_info where mn_num = i.mn_num and ent_code in

                #{entCode}

        )


order by update_time desc
